def parse_string(string):
    # Remove leading and trailing spaces from the string
    string = string.strip()

    # Initialize an empty dictionary to store the words and their repetitions
    word_counts = {}

    # Initialize an empty list to store the words in the order they appear
    words = []

    # Initialize a variable to keep track of the current word
    current_word = ''

    # Iterate over each character in the string
    for char in string:
        if char == ' ':
            # If a space is encountered, check if a word has been completed
            if current_word != '':
                words.append(current_word)
                current_word = ''
        elif char == '[':
            # If an opening square bracket is encountered, start parsing the repetition
            repetition = ''
        elif char == ']':
            # If a closing square bracket is encountered, add the word and its repetition to the dictionary
            if current_word != '':
                if repetition != '':
                    # If a repetition has been specified, convert it to an integer
                    repetition = int(repetition)
                else:
                    # If no repetition has been specified, default to 1
                    repetition = 1
                if current_word in word_counts:
                    # If the word already exists in the dictionary, add the repetition to the existing value
                    word_counts[current_word] += repetition
                else:
                    # If the word does not exist in the dictionary, add it with the repetition as the value
                    word_counts[current_word] = repetition
                # Add the word to the list of words in the order they appear
                words.append(current_word)
                current_word = ''
        elif char.isdigit():
            # If a digit is encountered, add it to the repetition string
            repetition += char
        else:
            # If any other character is encountered, add it to the current word
            current_word += char

    # If a word has not been completed after the last character, add it to the list of words
    if current_word != '':
        words.append(current_word)

    # Sort the list of words based on their repetitions and alphabetically
    words.sort(key=lambda x: (-word_counts[x], x))

    # Create a new dictionary with the sorted words and their repetitions
    sorted_word_counts = {}
    for word in words:
        sorted_word_counts[word] = word_counts[word]

    return sorted_word_counts

